<!DOCTYPE html>
<html>
<head>
  <title>Billiards</title>
  <style>
    body { margin: 0; overflow: hidden; background-color: #333; }
    canvas { display: block; }
    .aim-line { position: absolute; z-index: 10; border: 1px dashed white; }
  </style>
</head>
<body>
  <canvas id="gameCanvas"></canvas>

  <div style="position: absolute; top: 10px; left: 10px; color: white; font-family: sans-serif;">
    Instructions: Click and drag the cue ball to aim. Release to shoot! Press 'R' to reset.
  </div>

  <script>
    const canvas = document.getElementById('gameCanvas');
    const ctx = canvas.getContext('2d');
    canvas.width = 800;
    canvas.height = 600;
    const sim = {
      W: canvas.width,
      H: canvas.height,
      R: 20,
      balls: [],
      reset: function(balls) {
        this.balls = balls;
      },
      step: function(dt) {
        for (let i = 0; i < this.balls.length; i++) {
          const ball = this.balls[i];

          if (ball.cue) continue; // Don't update cue ball

          const x = ball.x;
          const y = ball.y;
          const vx = ball.vx;
          const vy = ball.vy;

          // Collision with walls
          if (x + vx < this.R || x + vx > this.W - this.R) vx *= -0.8; // Friction
          if (y + vy < this.R || y + vy > this.H - this.R) vy *= -0.8;

          // Ball-to-ball collision
          for (let j = i + 1; j < this.balls.length; j++) {
            const otherBall = this.balls[j];
            if (otherBall.cue) continue;

            const dx = otherBall.x - x;
            const dy = otherBall.y - y;
            const distSq = dx * dx + dy * dy;
            const ballRadiusSum = this.R + otherBall.R;

            if (distSq < (ballRadiusSum * ballRadiusSum)) {
              // Collision detected
              const nx = dx / distSq;
              const ny = dy / distSq;
              const dotProduct = dx * nx + dy * ny;

              if (dotProduct > 0) { // Collision is head-on or in front of the ball
                const relativeVelocityX = vx - otherBall.vx;
                const relativeVelocityY = vy - otherBall.vy;
                const collisionSpeed = Math.sqrt(relativeVelocityX * relativeVelocityX + relativeVelocityY * relativeVelocityY);

                const t = (collisionSpeed * (1 - dotProduct)) / (2 * ballRadiusSum); // Time of impact

                // Calculate new velocities
                vx += relativeVelocityX * t;
                vy += relativeVelocityY * t;
                otherBall.vx -= relativeVelocityX * t;
                otherBall.vy -= relativeVelocityY * t;
              }
            }
          }

          ball.x += vx * dt;
          ball.y += vy * dt;
        }
      },
      state: function() {
        return this.balls.map(ball => ({
          x: ball.x,
          y: ball.y,
          vx: ball.vx,
          vy: ball.vy,
          potted: ball.potted,
          cue: ball.cue
        }));
      },
      shoot: function(vx, vy) {
        // Find cue ball and set its velocity
        const cueBall = this.balls.find(ball => ball.cue);
        if (cueBall) {
          cueBall.vx = vx;
          cueBall.vy = vy;
        }
      },
      pause: function() {
        this.paused = true;
      },
      resume: function() {
        this.paused = false;
      },
      paused: false,
    };

    let lastX, lastY;
    let shooting = false;
    let shootVx = 0;
    let shootVy = 0;

    canvas.addEventListener('mousedown', (e) => {
      shooting = true;
      lastX = e.clientX - canvas.offsetLeft;
      lastY = e.clientY - canvas.offsetTop;
    });

    canvas.addEventListener('mouseup', () => {
      shooting = false;
      shootVx = (lastX - canvas.offsetLeft) / 10; // Scale to speed
      shootVy = (lastY - canvas.offsetTop) / 10;
    });

    canvas.addEventListener('mousemove', (e) => {
      if (!shooting) return;
      const x = e.clientX - canvas.offsetLeft;
      shootVx = (x - lastX) / 10;
      shootVy = (e.clientY - canvas.offsetTop) / 10;
    });

    sim.reset([{x: 250, y: 250, vx: 1, vy: 2, cue: true}, {x: 550, y: 250, vx: -1, vy: 2, cue: false},
                 {x: 375, y: 550, vx: 2, vy: -1, cue: false}, {x: 525, y: 550, vx: -2, vy: -1, cue: false}]);

    let dt = 0.05;
    let frame = 0;

    function animate() {
      requestAnimationFrame(animate);
      frame++;

      if (sim.paused) return;

      ctx.clearRect(0, 0, canvas.width, canvas.height);

      const state = sim.state();
      for (let i = 0; i < state.length; i++) {
        const ball = state[i];
        ctx.beginPath();
        ctx.arc(ball.x, ball.y, sim.R, 0, Math.PI * 2);
        ctx.fillStyle = ball.potted ? 'red' : 'white';
        ctx.fill();
      }

      // Draw aim line
      if (shooting) {
        ctx.beginPath();
        ctx.moveTo(lastX, lastY);
        ctx.lineTo(canvas.width - canvas.offsetLeft, canvas.offsetTop);
        ctx.strokeStyle = 'white';
        ctx.lineWidth = 2;
        ctx.stroke();
      }

      sim.step(dt);
    }

    animate();

    document.addEventListener('keydown', (e) => {
      if (e.key === 'r') {
        sim.reset([{x: 250, y: 250, vx: 1, vy: 2, cue: true}, {x: 550, y: 250, vx: -1, vy: 2, cue: false},
                 {x: 375, y: 550, vx: 2, vy: -1, cue: false}, {x: 525, y: 550, vx: -2, vy: -1, cue: false}]);
      }
    });

    window.sim = sim;
  </script>
</body>
</html>
